module RefModule(
input wire		regwrite_WB,
input wire [4:0] wa_WB,
input wire [4:0]ra1_EX,
input wire [4:0]ra2_EX,

output wire forwardA,forwardB

  wire temp1_(wa_WB == ra1_EX)&(regwrite_WB) = (wa_WB == ra1_EX)&(regwrite_WB);
  wire temp2_(wa_WB != 5'b0) = (wa_WB != 5'b0);
  assign forwardA = (temp1_(wa_WB == ra1_EX)&(regwrite_WB) & temp2_(wa_WB != 5'b0));
assign forwardB = ((wa_WB == ra2_EX)&(regwrite_WB)&(wa_WB != 5'b0));endmodule
